class Solution {
    public int countKDifference(int[] nums, int k) {
        Map<Integer, Integer> count = new HashMap<>();
        int res = 0;
        for (int num : nums) {
            res += count.getOrDefault(num - k, 0) + count.getOrDefault(num + k, 0);
            count.put(num, count.getOrDefault(num, 0) + 1);
        }
        return res;
    }
}
